"""Optimized circle packing for n=26 circles using scipy SLSQP optimization"""
import numpy as np
from scipy.optimize import minimize

def construct_packing():
    """
    Optimize all 52 position variables using SLSQP to maximize sum of radii.
    Radii are computed deterministically from positions via constraint propagation.

    Returns:
        Tuple of (centers, radii, sum_of_radii)
    """
    n = 26

    def compute_radii(positions):
        """Compute maximum valid radii from positions using iterative constraint propagation."""
        centers = positions.reshape(n, 2)
        radii = np.zeros(n)
        for i in range(n):
            x, y = centers[i]
            radii[i] = max(min(x, y, 1 - x, 1 - y), 1e-8)
        for _ in range(100):
            max_change = 0.0
            for i in range(n):
                for j in range(n):
                    if i != j:
                        dist = np.linalg.norm(centers[i] - centers[j])
                        max_r = dist - radii[j]
                        if max_r < radii[i] and max_r > 1e-10:
                            max_change = max(max_change, radii[i] - max_r)
                            radii[i] = max_r
            if max_change < 1e-10:
                break
        return np.maximum(radii, 1e-8)

    def objective(positions):
        """Negative sum of radii plus penalty for overlapping positions."""
        radii = compute_radii(positions)
        centers = positions.reshape(n, 2)
        penalty = 0.0
        for i in range(n):
            for j in range(i + 1, n):
                dist = np.linalg.norm(centers[i] - centers[j])
                if dist < 1e-6:
                    penalty += 1000.0
        return -np.sum(radii) + penalty

    best_sum = 0.0
    best_positions = None

    for trial in range(20):
        if trial == 0:
            x0 = np.zeros(2 * n)
            for i in range(n):
                x0[2*i] = 0.05 + (i % 5) * 0.19
                x0[2*i+1] = 0.05 + (i // 5) * 0.19
        else:
            x0 = np.random.uniform(0.05, 0.95, 2 * n)

        bounds = [(0.01, 0.99)] * (2 * n)
        result = minimize(objective, x0, method='SLSQP', bounds=bounds,
                         options={'maxiter': 1000, 'ftol': 1e-10})

        radii = compute_radii(result.x)
        sum_r = np.sum(radii)
        if sum_r > best_sum:
            best_sum = sum_r
            best_positions = result.x.copy()

    centers = best_positions.reshape(n, 2)
    radii = compute_radii(best_positions)
    return centers, radii, np.sum(radii)
